sql.where:

b.status <> 9

    AND (ou.phone LIKE concat('%', #{phone}, '%') OR hu.phone LIKE concat('%', #{phone}, '%'))


    AND b.status = #{status}



    AND b.created_date >= #{startDate}


    AND b.created_date < DATE_ADD(#{endDate}, INTERVAL 1 DAY)



    AND b.store_id IN (${storeIds})

mapper.select:
SELECT b.vip_benefit_id AS vipBenefitId, b.origin_user_id AS originUserId, ou.nickname AS originNickname, ou.phone AS originPhone, b.user_id AS userId, hu.nickname AS holderNickname, hu.phone AS holderPhone, b.vip_card_id AS vipCardId, c.card_name AS cardName, s.storeName AS storeName, b.source_order_no AS sourceOrderNo, b.origin_price AS originPrice, b.transfer_count AS transferCount, DATE_FORMAT(b.start_time, '%Y-%m-%d %H:%i:%s') AS startTime, DATE_FORMAT(b.expire_time, '%Y-%m-%d %H:%i:%s') AS expireTime, b.status AS status, DATE_FORMAT(b.created_date, '%Y-%m-%d %H:%i:%s') AS createdDate FROM vip_benefit b LEFT JOIN user_info ou ON b.origin_user_id = ou.userId LEFT JOIN user_info hu ON b.user_id = hu.userId LEFT JOIN vip_benefit_card c ON b.vip_card_id = c.vip_card_id LEFT JOIN store s ON s.storeId = b.store_id
ORDER BY b.created_date DESC
LIMIT #{offset}, #{limit}
